/**
 * API Route: Public Footer by Language
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export const dynamic = 'force-dynamic';
export const revalidate = 0;

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const language = searchParams.get('language') || 'en';

    console.log('Footer API: Fetching footer for language:', language);

    // دریافت فوتر فعال برای این زبان
    const footer = await prisma.footer.findFirst({
      where: {
        language,
        isActive: true
      }
    });

    if (!footer) {
      console.log('Footer API: No active footer found for', language);
      // Fallback به زبان پیشفرض
      const defaultFooter = await prisma.footer.findFirst({
        where: {
          language: 'en',
          isActive: true
        }
      });

      if (!defaultFooter) {
        console.log('Footer API: No default footer found either');
        return NextResponse.json({ 
          success: false,
          footer: null 
        });
      }

      return NextResponse.json({
        success: true,
        footer: {
          ...defaultFooter,
          contactInfo: defaultFooter.contactInfo ? JSON.parse(defaultFooter.contactInfo) : null,
          columns: JSON.parse(defaultFooter.columns || '[]'),
          bottomBar: defaultFooter.bottomBar ? JSON.parse(defaultFooter.bottomBar) : null,
          style: defaultFooter.style ? JSON.parse(defaultFooter.style) : null
        },
        fallback: true
      });
    }

    console.log('Footer API: Footer found:', footer.id);

    return NextResponse.json({
      success: true,
      footer: {
        ...footer,
        contactInfo: footer.contactInfo ? JSON.parse(footer.contactInfo) : null,
        columns: JSON.parse(footer.columns || '[]'),
        bottomBar: footer.bottomBar ? JSON.parse(footer.bottomBar) : null,
        style: footer.style ? JSON.parse(footer.style) : null
      }
    });

  } catch (error) {
    console.error('Footer API error:', error);
    return NextResponse.json({ 
      success: false,
      error: 'Failed to fetch footer',
      footer: null 
    }, { status: 500 });
  }
}
